    const graph: number[][] = Array.from({ length: c + 1 }, () => []);
    for (const [u, v] of connections) {
        graph[u].push(v);
        graph[v].push(u);
    }

    // Union-Find (Disjoint Set Union) data structure
    class DSU {
        parent: number[];
        rank: number[];
        constructor(size: number) {
            this.parent = Array.from({ length: size + 1 }, (_, i) => i);
            this.rank = Array.from({ length: size + 1 }, () => 1);
        }
        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }
        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);
            if (xRoot === yRoot) return false;
            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }
    }

    // Initialize DSU
    const dsu = new DSU(c);

    // Keep track of online stations
    const online: boolean[] = Array(c + 1).fill(true);

    // For each component, keep track of the minimum id
    const minId: number[] = Array(c + 1).fill(0);
    for (let i = 1; i <= c; i++) {
        minId[i] = i;
    }

    // Function to find the minimum id in the component of x
    function findMinId(x: number): number {
        const root = dsu.find(x);
        return minId[root];
    }

    // Function to update minId for a component
    function updateMinId(x: number, newMin: number): void {
        const root = dsu.find(x);
        minId[root] = Math.min(minId[root], newMin);
    }

    // Process queries
    const result: number[] = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            if (online[x]) {
                result.push(x);
            } else {
                const root = dsu.find(x);
                const minIdInComponent = findMinId(root);
                if (online[minIdInComponent]) {
                    result.push(minIdInComponent);
                } else {
                    result.push(-1);
                }
            }
        } else {
            online[x] = false;
        }
    }

    return result;
}

